# solution.py
"""In-memory Team Collaboration Manager.

A thread-safe, dependency-free implementation of a team collaboration
backend.  It manages users, projects, tasks, messaging, performance
metrics and reporting.  All persistence is in-memory and protected by a
single shared re-entrant lock so the manager is safe to use from multiple
threads.

The public surface (manager methods, enums, exceptions and data models)
is exercised by ``test_solution.py``.  Standard library only, ASCII only.
"""

import copy
import csv
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Dict, List, Optional, Set


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class UserRole(Enum):
    """Authorization role for a user."""

    MEMBER = "member"
    ADMIN = "admin"


class TaskStatus(Enum):
    """Lifecycle status for a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class ReportFormat(Enum):
    """Supported export formats for reports."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """Logical type of a generated report."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an action."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint is violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an action conflicts with current state."""


# ---------------------------------------------------------------------------
# Data models
# ---------------------------------------------------------------------------
@dataclass
class User:
    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int


@dataclass
class Task:
    id: int
    project_id: int
    title: str
    status: TaskStatus
    assignee_id: Optional[int]
    deadline: Optional[datetime]
    started_at: Optional[datetime]
    completed_at: Optional[datetime]
    created_at: datetime


@dataclass
class Attachment:
    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class Message:
    id: int
    author_id: int
    body: str
    project_id: Optional[int]
    task_id: Optional[int]
    attachments: List[Attachment] = field(default_factory=list)
    parent_id: Optional[int] = None
    created_at: Optional[datetime] = None
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str
    task_id: Optional[int]
    created_at: datetime


# ---------------------------------------------------------------------------
# Shared state
# ---------------------------------------------------------------------------
class _State:
    """Holds every in-memory collection plus the shared lock and clock."""

    def __init__(self, now):
        self.lock = threading.RLock()
        self.now = now
        self._counter = 0

        self.users: Dict[int, User] = {}
        self.projects: Dict[int, Project] = {}
        self.tasks: Dict[int, Task] = {}
        self.messages: Dict[int, Message] = {}
        self.ratings: Dict[int, Rating] = {}

        # Secondary indexes.
        self.username_index: Dict[str, int] = {}
        self.email_index: Dict[str, int] = {}
        self.tasks_by_project: Dict[int, Set[int]] = {}
        self.tasks_by_assignee: Dict[int, Set[int]] = {}
        self.messages_by_project: Dict[int, Set[int]] = {}
        self.messages_by_task: Dict[int, Set[int]] = {}
        self.ratings_by_ratee: Dict[int, Set[int]] = {}

    def next_id(self) -> int:
        self._counter += 1
        return self._counter


def _clone(obj):
    return copy.deepcopy(obj)


def _require_user(state: _State, user_id: int) -> User:
    user = state.users.get(user_id)
    if user is None:
        raise NotFoundError("user {0} not found".format(user_id))
    return user


def _require_project(state: _State, project_id: int) -> Project:
    project = state.projects.get(project_id)
    if project is None:
        raise NotFoundError("project {0} not found".format(project_id))
    return project


def _require_task(state: _State, task_id: int) -> Task:
    task = state.tasks.get(task_id)
    if task is None:
        raise NotFoundError("task {0} not found".format(task_id))
    return task


def _require_message(state: _State, message_id: int) -> Message:
    message = state.messages.get(message_id)
    if message is None:
        raise NotFoundError("message {0} not found".format(message_id))
    return message


def _valid_email(email: str) -> bool:
    if not email:
        return False
    if "@" not in email:
        return False
    local, _, domain = email.partition("@")
    return bool(local) and bool(domain)


# ---------------------------------------------------------------------------
# Component base
# ---------------------------------------------------------------------------
class _Component:
    """Base class for every store; all share the manager's lock."""

    def __init__(self, state: _State):
        self._state = state
        self._lock = state.lock


# ---------------------------------------------------------------------------
# User store
# ---------------------------------------------------------------------------
class _UserStore(_Component):
    def register_user(self, username, email, role=UserRole.MEMBER):
        with self._lock:
            if not isinstance(username, str) or not username.strip():
                raise ValidationError("username is required")
            if not isinstance(email, str) or not _valid_email(email.strip()):
                raise ValidationError("a valid email is required")
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            username = username.strip()
            email = email.strip()

            if username in self._state.username_index:
                raise DuplicateError("username already in use")
            if email in self._state.email_index:
                raise DuplicateError("email already in use")

            uid = self._state.next_id()
            user = User(
                id=uid,
                username=username,
                email=email,
                role=role,
                created_at=self._state.now(),
            )
            self._state.users[uid] = user
            self._state.username_index[username] = uid
            self._state.email_index[email] = uid
            return _clone(user)

    def get_user(self, user_id):
        with self._lock:
            return _clone(_require_user(self._state, user_id))

    def list_users(self):
        with self._lock:
            return [
                _clone(self._state.users[uid])
                for uid in sorted(self._state.users)
            ]

    def update_user(self, user_id, username=None, email=None, role=None):
        with self._lock:
            user = _require_user(self._state, user_id)

            if username is not None:
                if not isinstance(username, str) or not username.strip():
                    raise ValidationError("username is required")
                username = username.strip()
                if username != user.username:
                    if username in self._state.username_index:
                        raise DuplicateError("username already in use")

            if email is not None:
                if not isinstance(email, str) or not _valid_email(email.strip()):
                    raise ValidationError("a valid email is required")
                email = email.strip()
                if email != user.email:
                    if email in self._state.email_index:
                        raise DuplicateError("email already in use")

            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if username is not None and username != user.username:
                del self._state.username_index[user.username]
                self._state.username_index[username] = user.id
                user.username = username

            if email is not None and email != user.email:
                del self._state.email_index[user.email]
                self._state.email_index[email] = user.id
                user.email = email

            if role is not None:
                user.role = role

            return _clone(user)

    def delete_user(self, user_id):
        with self._lock:
            user = _require_user(self._state, user_id)

            for project in self._state.projects.values():
                if project.owner_id == user_id:
                    raise ConflictError("user owns one or more projects")

            assigned = self._state.tasks_by_assignee.get(user_id, set())
            for tid in assigned:
                task = self._state.tasks.get(tid)
                if task is not None and task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has open tasks")

            del self._state.users[user_id]
            self._state.username_index.pop(user.username, None)
            self._state.email_index.pop(user.email, None)
            self._state.tasks_by_assignee.pop(user_id, None)
            return None


# ---------------------------------------------------------------------------
# Project store
# ---------------------------------------------------------------------------
class _ProjectStore(_Component):
    def create_project(self, name, start_date, end_date, owner_id, description=""):
        with self._lock:
            _require_user(self._state, owner_id)
            if not isinstance(name, str) or not name.strip():
                raise ValidationError("project name is required")
            if end_date < start_date:
                raise ValidationError("end_date must not precede start_date")

            pid = self._state.next_id()
            project = Project(
                id=pid,
                name=name.strip(),
                description=description or "",
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
            )
            self._state.projects[pid] = project
            return _clone(project)

    def get_project(self, project_id):
        with self._lock:
            return _clone(_require_project(self._state, project_id))

    def list_projects(self):
        with self._lock:
            return [
                _clone(self._state.projects[pid])
                for pid in sorted(self._state.projects)
            ]

    def update_project(self, project_id, name=None, start_date=None,
                       end_date=None, description=None):
        with self._lock:
            project = _require_project(self._state, project_id)

            new_start = start_date if start_date is not None else project.start_date
            new_end = end_date if end_date is not None else project.end_date

            if name is not None:
                if not isinstance(name, str) or not name.strip():
                    raise ValidationError("project name is required")
            if new_end < new_start:
                raise ValidationError("end_date must not precede start_date")

            if name is not None:
                project.name = name.strip()
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date
            if description is not None:
                project.description = description

            return _clone(project)

    def delete_project(self, project_id):
        with self._lock:
            _require_project(self._state, project_id)

            task_ids = list(self._state.tasks_by_project.get(project_id, set()))
            for tid in task_ids:
                task = self._state.tasks.pop(tid, None)
                if task is not None and task.assignee_id is not None:
                    index = self._state.tasks_by_assignee.get(task.assignee_id)
                    if index is not None:
                        index.discard(tid)
                msg_ids = list(self._state.messages_by_task.get(tid, set()))
                for mid in msg_ids:
                    self._state.messages.pop(mid, None)
                self._state.messages_by_task.pop(tid, None)
            self._state.tasks_by_project.pop(project_id, None)

            msg_ids = list(self._state.messages_by_project.get(project_id, set()))
            for mid in msg_ids:
                self._state.messages.pop(mid, None)
            self._state.messages_by_project.pop(project_id, None)

            del self._state.projects[project_id]
            return None


# ---------------------------------------------------------------------------
# Task store
# ---------------------------------------------------------------------------
class _TaskStore(_Component):
    def create_task(self, project_id, title, assignee_id=None, deadline=None):
        with self._lock:
            project = _require_project(self._state, project_id)
            if not isinstance(title, str) or not title.strip():
                raise ValidationError("task title is required")
            if assignee_id is not None:
                _require_user(self._state, assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline must not precede project start")

            tid = self._state.next_id()
            task = Task(
                id=tid,
                project_id=project_id,
                title=title.strip(),
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                started_at=None,
                completed_at=None,
                created_at=self._state.now(),
            )
            self._state.tasks[tid] = task
            self._state.tasks_by_project.setdefault(project_id, set()).add(tid)
            if assignee_id is not None:
                self._state.tasks_by_assignee.setdefault(
                    assignee_id, set()
                ).add(tid)
            return _clone(task)

    def get_task(self, task_id):
        with self._lock:
            return _clone(_require_task(self._state, task_id))

    def list_tasks_by_project(self, project_id):
        with self._lock:
            _require_project(self._state, project_id)
            ids = self._state.tasks_by_project.get(project_id, set())
            return [_clone(self._state.tasks[tid]) for tid in sorted(ids)]

    def list_tasks_by_assignee(self, assignee_id):
        with self._lock:
            _require_user(self._state, assignee_id)
            ids = self._state.tasks_by_assignee.get(assignee_id, set())
            return [_clone(self._state.tasks[tid]) for tid in sorted(ids)]

    def _set_assignee(self, task, new_assignee_id):
        if task.assignee_id is not None:
            index = self._state.tasks_by_assignee.get(task.assignee_id)
            if index is not None:
                index.discard(task.id)
        task.assignee_id = new_assignee_id
        if new_assignee_id is not None:
            self._state.tasks_by_assignee.setdefault(
                new_assignee_id, set()
            ).add(task.id)

    def assign_task(self, task_id, assignee_id):
        with self._lock:
            task = _require_task(self._state, task_id)
            _require_user(self._state, assignee_id)
            self._set_assignee(task, assignee_id)
            return _clone(task)

    def reassign_task(self, task_id, new_assignee_id):
        with self._lock:
            task = _require_task(self._state, task_id)
            _require_user(self._state, new_assignee_id)
            self._set_assignee(task, new_assignee_id)
            return _clone(task)

    def unassign_task(self, task_id):
        with self._lock:
            task = _require_task(self._state, task_id)
            self._set_assignee(task, None)
            return _clone(task)

    def set_deadline(self, task_id, deadline):
        with self._lock:
            task = _require_task(self._state, task_id)
            if deadline is not None:
                project = self._state.projects.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError(
                        "deadline must not precede project start"
                    )
            task.deadline = deadline
            return _clone(task)

    def update_status(self, task_id, status):
        with self._lock:
            task = _require_task(self._state, task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")

            now = self._state.now()
            if status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            elif status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now

            task.status = status
            return _clone(task)


# ---------------------------------------------------------------------------
# Message store
# ---------------------------------------------------------------------------
class _MessageStore(_Component):
    def post_message(self, author_id, body, project_id=None, task_id=None,
                     attachments=None, parent_id=None):
        with self._lock:
            _require_user(self._state, author_id)

            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id is required"
                )

            if project_id is not None:
                _require_project(self._state, project_id)
            if task_id is not None:
                _require_task(self._state, task_id)
            if parent_id is not None:
                _require_message(self._state, parent_id)

            attachment_specs = attachments or []
            if (body is None or not str(body).strip()) and not attachment_specs:
                raise ValidationError(
                    "message body or an attachment is required"
                )

            now = self._state.now()
            built = []
            for filename, data in attachment_specs:
                built.append(self._build_attachment(author_id, filename, data, now))

            mid = self._state.next_id()
            message = Message(
                id=mid,
                author_id=author_id,
                body=body if body is not None else "",
                project_id=project_id,
                task_id=task_id,
                attachments=built,
                parent_id=parent_id,
                created_at=now,
                edited_at=None,
            )
            self._state.messages[mid] = message
            if project_id is not None:
                self._state.messages_by_project.setdefault(
                    project_id, set()
                ).add(mid)
            if task_id is not None:
                self._state.messages_by_task.setdefault(task_id, set()).add(mid)
            return _clone(message)

    def _build_attachment(self, uploader_id, filename, data, when):
        size = len(data) if data is not None else 0
        return Attachment(
            filename=filename,
            size=size,
            uploaded_by=uploader_id,
            uploaded_at=when,
        )

    def edit_message(self, message_id, editor_id, new_body):
        with self._lock:
            message = _require_message(self._state, message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit a message")
            if (new_body is None or not str(new_body).strip()) and not message.attachments:
                raise ValidationError("message body is required")
            message.body = new_body if new_body is not None else ""
            message.edited_at = self._state.now()
            return _clone(message)

    def add_attachment(self, message_id, uploader_id, filename, data):
        with self._lock:
            message = _require_message(self._state, message_id)
            if message.author_id != uploader_id:
                raise AuthorizationError(
                    "only the author may add attachments"
                )
            if not isinstance(filename, str) or not filename.strip():
                raise ValidationError("filename is required")
            attachment = self._build_attachment(
                uploader_id, filename, data, self._state.now()
            )
            message.attachments.append(attachment)
            return _clone(message)

    def list_messages_by_project(self, project_id):
        with self._lock:
            _require_project(self._state, project_id)
            ids = self._state.messages_by_project.get(project_id, set())
            return [_clone(self._state.messages[mid]) for mid in sorted(ids)]

    def list_messages_by_task(self, task_id):
        with self._lock:
            _require_task(self._state, task_id)
            ids = self._state.messages_by_task.get(task_id, set())
            return [_clone(self._state.messages[mid]) for mid in sorted(ids)]

    def delete_message(self, message_id, requester_id):
        with self._lock:
            message = _require_message(self._state, message_id)
            if message.author_id != requester_id:
                raise AuthorizationError(
                    "only the author may delete a message"
                )
            if message.project_id is not None:
                index = self._state.messages_by_project.get(message.project_id)
                if index is not None:
                    index.discard(message_id)
            if message.task_id is not None:
                index = self._state.messages_by_task.get(message.task_id)
                if index is not None:
                    index.discard(message_id)
            del self._state.messages[message_id]
            return None


# ---------------------------------------------------------------------------
# Performance store
# ---------------------------------------------------------------------------
class _PerformanceStore(_Component):
    def _user_tasks(self, user_id):
        ids = self._state.tasks_by_assignee.get(user_id, set())
        return [self._state.tasks[tid] for tid in ids if tid in self._state.tasks]

    def get_completion_rate(self, user_id):
        with self._lock:
            _require_user(self._state, user_id)
            tasks = self._user_tasks(user_id)
            if not tasks:
                return 0.0
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            return completed / len(tasks)

    def get_average_completion_time(self, user_id):
        with self._lock:
            _require_user(self._state, user_id)
            durations = []
            for task in self._user_tasks(user_id):
                if (
                    task.status == TaskStatus.COMPLETED
                    and task.started_at is not None
                    and task.completed_at is not None
                ):
                    durations.append(
                        (task.completed_at - task.started_at).total_seconds()
                    )
            if not durations:
                return None
            return sum(durations) / len(durations)

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None):
        with self._lock:
            _require_user(self._state, rater_id)
            _require_user(self._state, ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("a user cannot rate themselves")
            if not isinstance(score, int) or isinstance(score, bool):
                raise ValidationError("score must be an integer 1..5")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            if task_id is not None:
                _require_task(self._state, task_id)

            rid = self._state.next_id()
            rating = Rating(
                id=rid,
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=self._state.now(),
            )
            self._state.ratings[rid] = rating
            self._state.ratings_by_ratee.setdefault(ratee_id, set()).add(rid)
            return _clone(rating)

    def _ratings_for(self, user_id):
        ids = self._state.ratings_by_ratee.get(user_id, set())
        return [self._state.ratings[rid] for rid in sorted(ids)]

    def get_ratings_summary(self, user_id):
        with self._lock:
            _require_user(self._state, user_id)
            ratings = self._ratings_for(user_id)
            count = len(ratings)
            average = (
                sum(r.score for r in ratings) / count if count else 0.0
            )
            return {
                "count": count,
                "average": average,
                "ratings": [_clone(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id):
        with self._lock:
            _require_user(self._state, user_id)
            tasks = self._user_tasks(user_id)
            total = len(tasks)
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            in_progress = sum(
                1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
            )
            not_started = sum(
                1 for t in tasks if t.status == TaskStatus.NOT_STARTED
            )
            completion_rate = completed / total if total else 0.0

            durations = [
                (t.completed_at - t.started_at).total_seconds()
                for t in tasks
                if t.status == TaskStatus.COMPLETED
                and t.started_at is not None
                and t.completed_at is not None
            ]
            average_completion_time = (
                sum(durations) / len(durations) if durations else None
            )

            ratings = self._ratings_for(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
                if rating_count
                else 0.0
            )

            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completion_rate,
                "average_completion_time": average_completion_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
            }


# ---------------------------------------------------------------------------
# Report store
# ---------------------------------------------------------------------------
class _ReportStore(_Component):
    def __init__(self, state, performance):
        super().__init__(state)
        self._performance = performance

    def project_progress_report(self, project_id):
        with self._lock:
            _require_project(self._state, project_id)
            ids = self._state.tasks_by_project.get(project_id, set())
            tasks = [self._state.tasks[tid] for tid in ids]
            now = self._state.now()

            status_counts = {status.value: 0 for status in TaskStatus}
            overdue = 0
            per_assignee = {}
            completed = 0

            for task in tasks:
                status_counts[task.status.value] += 1
                if task.status == TaskStatus.COMPLETED:
                    completed += 1
                if (
                    task.deadline is not None
                    and task.deadline < now
                    and task.status != TaskStatus.COMPLETED
                ):
                    overdue += 1
                if task.assignee_id is not None:
                    bucket = per_assignee.setdefault(
                        task.assignee_id,
                        {"total": 0, "completed": 0},
                    )
                    bucket["total"] += 1
                    if task.status == TaskStatus.COMPLETED:
                        bucket["completed"] += 1

            total = len(tasks)
            for bucket in per_assignee.values():
                bucket["completion_rate"] = (
                    bucket["completed"] / bucket["total"]
                    if bucket["total"]
                    else 0.0
                )

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completed / total if total else 0.0,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None):
        with self._lock:
            if project_id is not None:
                _require_project(self._state, project_id)
                task_ids = self._state.tasks_by_project.get(project_id, set())
                tasks = [self._state.tasks[tid] for tid in task_ids]
            else:
                tasks = list(self._state.tasks.values())

            by_assignee = {}
            for task in tasks:
                if task.assignee_id is not None:
                    by_assignee.setdefault(task.assignee_id, []).append(task)

            rows = []
            for uid in sorted(by_assignee):
                rows.append(self._performance_row(uid, by_assignee[uid]))

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id):
        with self._lock:
            _require_user(self._state, user_id)
            ids = self._state.tasks_by_assignee.get(user_id, set())
            tasks = [self._state.tasks[tid] for tid in sorted(ids)]
            row = self._performance_row(user_id, tasks)

            task_rows = []
            for task in tasks:
                task_rows.append(
                    {
                        "task_id": task.id,
                        "title": task.title,
                        "status": task.status.value,
                        "started_at": task.started_at,
                        "completed_at": task.completed_at,
                        "deadline": task.deadline,
                    }
                )

            report = {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "tasks": task_rows,
            }
            report.update(
                {
                    key: row[key]
                    for key in (
                        "total_tasks",
                        "completed_tasks",
                        "completion_rate",
                        "average_completion_time",
                        "rating_count",
                        "rating_average",
                    )
                }
            )
            return report

    def _performance_row(self, user_id, tasks):
        total = len(tasks)
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        durations = [
            (t.completed_at - t.started_at).total_seconds()
            for t in tasks
            if t.status == TaskStatus.COMPLETED
            and t.started_at is not None
            and t.completed_at is not None
        ]
        average_completion_time = (
            sum(durations) / len(durations) if durations else None
        )
        ratings = [
            self._state.ratings[rid]
            for rid in self._state.ratings_by_ratee.get(user_id, set())
        ]
        rating_count = len(ratings)
        rating_average = (
            sum(r.score for r in ratings) / rating_count
            if rating_count
            else 0.0
        )
        return {
            "user_id": user_id,
            "total_tasks": total,
            "completed_tasks": completed,
            "completion_rate": completed / total if total else 0.0,
            "average_completion_time": average_completion_time,
            "rating_count": rating_count,
            "rating_average": rating_average,
        }

    # -- export -----------------------------------------------------------
    def export_report(self, report, report_format):
        with self._lock:
            if not isinstance(report, dict):
                raise ValidationError("report must be a dict")
            if not isinstance(report_format, ReportFormat):
                raise ValidationError("report_format must be a ReportFormat")
            if report_format == ReportFormat.CSV:
                return self._to_csv(report)
            return self._to_pdf(report)

    def _to_csv(self, report):
        out = io.StringIO()
        writer = csv.writer(out)
        rtype = report.get("report_type")

        if rtype == ReportType.TEAM_PERFORMANCE.value:
            header = [
                "user_id",
                "total_tasks",
                "completed_tasks",
                "completion_rate",
                "average_completion_time",
                "rating_count",
                "rating_average",
            ]
            writer.writerow(header)
            for row in report.get("rows", []):
                writer.writerow([row.get(col, "") for col in header])
        elif rtype == ReportType.INDIVIDUAL_PERFORMANCE.value:
            header = [
                "task_id",
                "title",
                "status",
                "started_at",
                "completed_at",
                "deadline",
            ]
            writer.writerow(header)
            for task in report.get("tasks", []):
                writer.writerow([task.get(col, "") for col in header])
        elif rtype == ReportType.PROJECT_PROGRESS.value:
            writer.writerow(["field", "value"])
            writer.writerow(["project_id", report.get("project_id", "")])
            writer.writerow(["total_tasks", report.get("total_tasks", "")])
            writer.writerow(
                ["completion_rate", report.get("completion_rate", "")]
            )
            writer.writerow(["overdue_tasks", report.get("overdue_tasks", "")])
            for status, count in report.get("status_counts", {}).items():
                writer.writerow(["status:{0}".format(status), count])
        else:
            keys = list(report.keys())
            writer.writerow(keys)
            writer.writerow([self._scalar(report[key]) for key in keys])

        return out.getvalue()

    def _scalar(self, value):
        if isinstance(value, (list, dict)):
            return "{0} items".format(len(value))
        return value

    def _report_lines(self, report):
        lines = ["Report: {0}".format(report.get("report_type", "report"))]
        for key, value in report.items():
            if key == "report_type":
                continue
            if isinstance(value, (list, dict)):
                lines.append("{0}: {1} items".format(key, len(value)))
            else:
                lines.append("{0}: {1}".format(key, value))
        return lines

    def _to_pdf(self, report):
        return _build_pdf(self._report_lines(report))


def _pdf_escape(text):
    return (
        str(text)
        .replace("\\", "\\\\")
        .replace("(", "\\(")
        .replace(")", "\\)")
    )


def _build_pdf(lines):
    """Build a minimal but structurally valid single-page PDF document."""

    commands = ["BT", "/F1 12 Tf", "72 760 Td", "14 TL"]
    first = True
    for line in lines:
        if first:
            commands.append("({0}) Tj".format(_pdf_escape(line)))
            first = False
        else:
            commands.append("T*")
            commands.append("({0}) Tj".format(_pdf_escape(line)))
    commands.append("ET")
    content = "\n".join(commands)

    objects = [
        "<< /Type /Catalog /Pages 2 0 R >>",
        "<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
        (
            "<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
            "/Contents 4 0 R /Resources << /Font << /F1 5 0 R >> >> >>"
        ),
        "<< /Length {0} >>\nstream\n{1}\nendstream".format(
            len(content.encode("latin-1")), content
        ),
        "<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
    ]

    header = "%PDF-1.4\n"
    parts = [header]
    offsets = []
    cursor = len(header.encode("latin-1"))
    for index, body in enumerate(objects, start=1):
        chunk = "{0} 0 obj\n{1}\nendobj\n".format(index, body)
        offsets.append(cursor)
        parts.append(chunk)
        cursor += len(chunk.encode("latin-1"))

    xref_offset = cursor
    count = len(objects) + 1
    xref = ["xref", "0 {0}".format(count), "0000000000 65535 f "]
    for offset in offsets:
        xref.append("{0:010d} 00000 n ".format(offset))
    xref_block = "\n".join(xref) + "\n"

    trailer = (
        "trailer\n<< /Size {0} /Root 1 0 R >>\nstartxref\n{1}\n%%EOF\n".format(
            count, xref_offset
        )
    )

    parts.append(xref_block)
    parts.append(trailer)
    return "".join(parts).encode("latin-1")


